// Valida y normaliza los parámetros de búsqueda CEC.
const src = $input.first().json;
const body = src.body || src;
const type = (body.type || '').toString().trim().toLowerCase();
const q     = (body.q     || '').toString().trim();
const limit = Math.min(Math.max(parseInt(body.limit ?? 25, 10) || 25, 1), 100);

if (type !== 'panel' && type !== 'inverter') {
  return [{ json: { ok: false, reason: 'invalid_type', detail: "type debe ser 'panel' o 'inverter'" } }];
}
return [{ json: { ok: true, type, q, limit } }];

// Normaliza resultados al formato esperado por los servicios frontend.
const rows = $input.all().map(item => item.json);
const input = $('Validar input').first().json;
const type = input.type;

const safeJson = (v) => {
  if (typeof v !== 'string') return v || {};
  try { return JSON.parse(v); } catch (_) { return {}; }
};

const results = rows.map(r => {
  const raw = safeJson(r.raw);
  if (type === 'panel') {
    return {
      id: 'cec_' + r.id,
      brand: r.manufacturer,
      model: r.model,
      fullName: `${r.manufacturer} ${r.model}`,
      wp: r.pmax_w ? Number(r.pmax_w) : null,
      voc: r.voc ? Number(r.voc) : null,
      vmp: r.vmp ? Number(r.vmp) : null,
      isc: r.isc ? Number(r.isc) : null,
      imp: r.imp ? Number(r.imp) : null,
      efficiency: r.efficiency ? Number(r.efficiency) : null,
      length_m: r.length_m ? Number(r.length_m) : null,
      width_m:  r.width_m  ? Number(r.width_m)  : null,
      bifacial: r.bifacial || false,
      tempCoeffPmax: raw.gamma_r ? Number(raw.gamma_r) : null,
      tempCoeffVoc:  raw.beta_oc  ? Number(raw.beta_oc)  : null,
      cellCount:     raw.N_s      ? Number(raw.N_s)      : null,
      technology:    raw.Technology || 'Mono-c-Si',
      source: 'CEC/Postgres',
    };
  } else {
    return {
      id: 'cec_' + r.id,
      brand: r.manufacturer,
      model: r.model,
      fullName: `${r.manufacturer} ${r.model}`,
      kw: r.pac_w ? Number(r.pac_w) / 1000 : null,
      acMaxContinuousW: r.pac_w ? Number(r.pac_w) : null,
      vocMax:    r.vdc_max    ? Number(r.vdc_max)    : null,
      mpptVmin:  r.vdc_min    ? Number(r.vdc_min)    : null,
      mpptCount: r.mppt_count ? Number(r.mppt_count) : null,
      phase: r.phase ? Number(r.phase) : 1,
      source: 'CEC/Postgres',
    };
  }
});

return [{ json: {
  ok: true,
  type,
  count: results.length,
  results,
  source: 'NREL SAM / CEC (Postgres)',
} }];

const err = $input.first();
const detail = err?.json?.message || err?.json?.error || 'Error consultando Postgres';
return [{ json: { ok: false, reason: 'db_error', detail } }];
